"use client";

import { useState } from "react";
import axios from "axios";

export default function Home() {
  const [skills, setSkills] = useState("");
  const [role, setRole] = useState("");
  const [country, setCountry] = useState("Germany");

  const [data, setData] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  const analyze = async () => {
    setLoading(true);

    try {
      const res = await axios.post(
        "http://127.0.0.1:8000/analyze",
        {
          skills,
          role,
          country,
        }
      );

      setData(res.data);
    } catch (err) {
      alert("Backend connection failed");
    }

    setLoading(false);
  };

  return (
    <div
      style={{
        background: "#0f172a",
        minHeight: "100vh",
        color: "white",
        padding: "30px",
        fontFamily: "Arial",
      }}
    >
      <h1 style={{ textAlign: "center" }}>
        🌍 AI Global Career Navigator
      </h1>

      <div
        style={{
          maxWidth: "600px",
          margin: "30px auto",
          background: "#1e293b",
          padding: "20px",
          borderRadius: "12px",
        }}
      >
        <input
          placeholder="Skills"
          style={inputStyle}
          onChange={(e) => setSkills(e.target.value)}
        />

        <input
          placeholder="Target Role"
          style={inputStyle}
          onChange={(e) => setRole(e.target.value)}
        />

        <select
          style={inputStyle}
          onChange={(e) => setCountry(e.target.value)}
        >
          <option>Germany</option>
          <option>Canada</option>
          <option>Netherlands</option>
          <option>Australia</option>
          <option>UK</option>
        </select>

        <button
          onClick={analyze}
          style={buttonStyle}
        >
          {loading
            ? "Analyzing..."
            : "Run Career Intelligence"}
        </button>
      </div>

      {data && (
        <div style={{ maxWidth: "1200px", margin: "auto" }}>
          <div
            style={{
              display: "grid",
              gridTemplateColumns:
                "repeat(auto-fit,minmax(220px,1fr))",
              gap: "20px",
            }}
          >
            <Card
              title="Career Score"
              value={data.career_score}
            />

            <Card
              title="Visa Score"
              value={data.visa_score}
            />

            <Card
              title="Competition"
              value={data.competition}
            />

            <Card
              title="Salary Range"
              value={data.salary_range}
            />
          </div>

          <Section title="Missing Skills">
            {data.missing_skills.map(
              (s: string, i: number) => (
                <p key={i}>❌ {s}</p>
              )
            )}
          </Section>

          <Section title="Top Countries">
            {data.top_countries.map(
              (c: string, i: number) => (
                <p key={i}>🌍 {c}</p>
              )
            )}
          </Section>

          <Section title="Target Companies">
            {data.top_companies.map(
              (c: string, i: number) => (
                <p key={i}>🏢 {c}</p>
              )
            )}
          </Section>

          <Section title="Roadmap">
            {data.roadmap.map(
              (r: string, i: number) => (
                <p key={i}>✅ {r}</p>
              )
            )}
          </Section>

          <Section title="AI Strategy">
            <p
              style={{
                whiteSpace: "pre-line",
              }}
            >
              {data.ai_insight}
            </p>
          </Section>
        </div>
      )}
    </div>
  );
}

function Card({
  title,
  value,
}: {
  title: string;
  value: any;
}) {
  return (
    <div
      style={{
        background: "#1e293b",
        padding: "20px",
        borderRadius: "12px",
      }}
    >
      <h3>{title}</h3>
      <h2>{value}</h2>
    </div>
  );
}

function Section({
  title,
  children,
}: any) {
  return (
    <div
      style={{
        background: "#1e293b",
        padding: "20px",
        borderRadius: "12px",
        marginTop: "20px",
      }}
    >
      <h2>{title}</h2>
      {children}
    </div>
  );
}

const inputStyle = {
  width: "100%",
  padding: "12px",
  marginBottom: "12px",
  borderRadius: "8px",
  border: "none",
};

const buttonStyle = {
  width: "100%",
  padding: "12px",
  borderRadius: "8px",
  border: "none",
  background: "#2563eb",
  color: "white",
  cursor: "pointer",
};